from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
profiles = db.profiles

@app.route('/profile', methods=['POST'])
def create_profile():
    profile_data = request.get_json()
    result = profiles.insert_one(profile_data)
    return jsonify({"message": "Profile created successfully", "id": str(result.inserted_id)}), 201

@app.route('/profiles', methods=['GET'])
def get_profiles():
    query = request.args.to_dict()
    cursor = profiles.find(query)
    profile_list = list(cursor)
    for profile in profile_list:
        profile['_id'] = str(profile['_id'])
    return jsonify(profile_list)

@app.route('/profile/aggregate', methods=['POST'])
def aggregate_profiles():
    pipeline = request.get_json()
    result = profiles.aggregate(pipeline)
    result_list = list(result)
    for item in result_list:
        if '_id' in item and isinstance(item['_id'], object):
            item['_id'] = str(item['_id'])
    return jsonify(result_list)

if __name__ == '__main__':
    app.run(debug=True)